INSERT INTO `response_templates` (`id`, `guru_type`, `name`, `content`, `category`, `default_status`, `is_active`, `use_count`, `created_by`, `created_at`, `updated_at`) VALUES (1, ''Guru_BK'', ''Konsultasi Jurusan'', ''Terima kasih atas konsultasi Anda. Untuk pemilihan jurusan yang tepat, saya sarankan: 1. Kenali minat dan bakat Anda, 2. Pelajari prospek kerja jurusan tersebut, 3. Konsultasi dengan orang tua. Mari kita diskusikan lebih lanjut.'', ''Konseling'', ''Disetujui'', 1, 1, NULL, ''2026-02-09 12:16:43'', ''2026-02-09 13:53:31'');
INSERT INTO `response_templates` (`id`, `guru_type`, `name`, `content`, `category`, `default_status`, `is_active`, `use_count`, `created_by`, `created_at`, `updated_at`) VALUES (2, ''Guru_Kurikulum'', ''Tambahan Pelajaran'', ''Mengenai permintaan tambahan pelajaran, kami akan mengadakan kelas tambahan setiap hari Jumat sore pukul 14.00-16.00. Silakan daftar di ruang guru kurikulum.'', ''Akademik'', ''Disetujui'', 1, 0, NULL, ''2026-02-09 12:16:43'', ''2026-02-09 12:16:43'');
INSERT INTO `response_templates` (`id`, `guru_type`, `name`, `content`, `category`, `default_status`, `is_active`, `use_count`, `created_by`, `created_at`, `updated_at`) VALUES (3, ''Guru_Sarana'', ''Perbaikan Fasilitas'', ''Laporan kerusakan telah diterima. Tim maintenance akan memeriksa dan memperbaiki dalam waktu 3-5 hari kerja. Terima kasih atas laporannya.'', ''Fasilitas'', ''Diproses'', 1, 0, NULL, ''2026-02-09 12:16:43'', ''2026-02-09 12:16:43'');
